// Sadece 'sisti' olayinda kurtarma: Servis B onbellegini temizle (cache eviction)
const event = $('Cache Uyari Webhook').first().json.body.event || '';
if (event === 'sisti') {
  const { execSync } = require('child_process');
  try { execSync('wget -qO- --timeout=5 http://servis_b:5000/cache/evict', { timeout: 8000 }); } catch (e) {}
}
return $input.all();
